"""Pre-generation, generator-judged contradiction discovery.

Candidate pairs come only from scoped evidence rows that share prompt-derived
content vocabulary or a reported measure.  The judge classifies the relationship
between the two supplied claims; only confident, comparable conflicts survive.
"""
from __future__ import annotations

import json
import re
from collections import Counter
from collections.abc import Callable, Mapping, Sequence
from typing import Any

from src.polaris_graph.settings import resolve


_TRUE_VALUES = frozenset({"1", "true", "yes", "on"})
_TOKEN_RE = re.compile(r"[^\W\d_][\w'-]+", re.UNICODE)
_UNIT_RE = re.compile(r"(?:%|[A-Za-z]+(?:/[A-Za-z]+)?)")
_NUMBER_WITH_UNIT_RE = re.compile(
    r"[-+]?\d+(?:[.,]\d+)?\s*(%|[A-Za-z]+(?:/[A-Za-z]+)?)",
)
_STOPWORDS = frozenset({
    "about", "after", "also", "among", "and", "are", "because", "before",
    "between", "but", "can", "could", "during", "for", "from", "had", "has",
    "have", "into", "its", "may", "more", "not", "over", "reported", "study",
    "than", "that", "the", "their", "these", "this", "those", "through", "under",
    "using", "was", "were", "which", "while", "with", "within", "would",
})


def contradiction_mining_enabled() -> bool:
    """Return the central default-off switch at call time."""

    return (resolve("PG_CONTRADICTION_MINING") or "").strip().lower() in _TRUE_VALUES


def _row_text(row: Mapping[str, Any]) -> str:
    return " ".join(
        str(row.get(name) or "")
        for name in (
            "title", "source_title", "subject", "predicate", "measure", "metric",
            "endpoint", "population", "period", "statement", "direct_quote", "snippet",
        )
    ).strip()


def _row_tokens(row: Mapping[str, Any]) -> frozenset[str]:
    return frozenset(
        token.casefold()
        for token in _TOKEN_RE.findall(_row_text(row))
        if len(token) > 2 and token.casefold() not in _STOPWORDS
    )


def _row_measures(row: Mapping[str, Any]) -> frozenset[str]:
    declared = {
        str(row.get(name) or "").strip().casefold()
        for name in ("measure", "metric", "endpoint", "outcome")
        if str(row.get(name) or "").strip()
    }
    units = {
        match.group(1).casefold()
        for match in _NUMBER_WITH_UNIT_RE.finditer(_row_text(row))
        if _UNIT_RE.fullmatch(match.group(1))
    }
    return frozenset(declared | units)


def cluster_candidate_pairs(
    rows: Sequence[Mapping[str, Any]],
) -> list[tuple[dict[str, Any], dict[str, Any]]]:
    """Return unique pairs sharing a discriminating term or reported measure.

    Term frequency is computed from this evidence pool, so no domain vocabulary
    is embedded. Each row uses its least-frequent repeated terms as cluster anchors.
    """

    copied = [dict(row) for row in rows]
    tokens = [_row_tokens(row) for row in copied]
    measures = [_row_measures(row) for row in copied]
    frequencies = Counter(token for row_tokens in tokens for token in row_tokens)
    anchors: list[frozenset[str]] = []
    for row_tokens in tokens:
        repeated = [token for token in row_tokens if frequencies[token] > 1]
        if not repeated:
            anchors.append(frozenset())
            continue
        minimum_frequency = min(frequencies[token] for token in repeated)
        anchors.append(frozenset(
            token for token in repeated if frequencies[token] == minimum_frequency
        ))
    row_count = len(copied)
    pairs: list[tuple[dict[str, Any], dict[str, Any]]] = []
    for left_index, left in enumerate(copied):
        for right_index in range(left_index + 1, row_count):
            shared_terms = anchors[left_index] & anchors[right_index]
            shared_measures = measures[left_index] & measures[right_index]
            if shared_terms or shared_measures:
                pairs.append((left, copied[right_index]))
    return pairs


def _judge_prompt(
    research_question: str,
    left: Mapping[str, Any],
    right: Mapping[str, Any],
) -> str:
    left_id = str(left.get("evidence_id") or left.get("source_url") or "row_a")
    right_id = str(right.get("evidence_id") or right.get("source_url") or "row_b")
    return f"""You are comparing two scoped evidence rows before a research report is written.

Research question:
{research_question}

Row A ({left_id}):
{_row_text(left)}

Row B ({right_id}):
{_row_text(right)}

Decide whether the rows make incompatible empirical claims about the SAME quantity or relationship.
Different populations, methods, periods, measures, endpoints, or observed-versus-modelled results
are not automatically conflicts. If the claims cannot be compared on the same basis, classify them
as non_comparable. If they can both be true, classify them as compatible.

Return one JSON object only:
{{
  "classification": "conflict" | "compatible" | "non_comparable",
  "confident": true | false,
  "reason": "one sentence stating the exact disagreement or comparability boundary",
  "subject": "shared subject",
  "predicate": "shared quantity or relationship",
  "measure": "shared measure, or empty string"
}}"""


def _parse_object(raw: str) -> dict[str, Any]:
    text = str(raw or "").strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text, flags=re.IGNORECASE)
        text = re.sub(r"\s*```$", "", text)
    try:
        value = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, flags=re.DOTALL)
        if match is None:
            return {}
        try:
            value = json.loads(match.group(0))
        except json.JSONDecodeError:
            return {}
    return value if isinstance(value, dict) else {}


def find_contradictions(
    rows: Sequence[Mapping[str, Any]],
    research_question: str,
    judge_fn: Callable[[str], str],
) -> list[dict[str, Any]]:
    """Judge candidate pairs and retain only confident comparable conflicts."""

    conflicts: list[dict[str, Any]] = []
    for left, right in cluster_candidate_pairs(rows):
        verdict = _parse_object(judge_fn(_judge_prompt(research_question, left, right)))
        if verdict.get("classification") != "conflict" or verdict.get("confident") is not True:
            continue
        left_id = str(left.get("evidence_id") or left.get("source_url") or "")
        right_id = str(right.get("evidence_id") or right.get("source_url") or "")
        reason = " ".join(str(verdict.get("reason") or "").split())
        if not left_id or not right_id or not reason:
            continue
        conflicts.append({
            "evidence_ids": [left_id, right_id],
            "subject": str(verdict.get("subject") or "").strip(),
            "predicate": str(verdict.get("predicate") or "").strip(),
            "measure": str(verdict.get("measure") or "").strip(),
            "reason": reason,
            "comparison_status": "conflict",
            "confidence": "confirmed",
        })
    return conflicts

"""Pre-generation proposition packs and a report-wide relation map.

The structures contain only fields already present in admitted evidence and
only reorder or group existing section membership.
"""
from __future__ import annotations

import json
import re
from collections.abc import Mapping, Sequence
from typing import Any

from src.polaris_graph.settings import resolve


_TRUE_VALUES = frozenset({"1", "true", "yes", "on"})
_TOKEN_RE = re.compile(r"[^\W\d_][\w'-]+", re.UNICODE)
_STOPWORDS = frozenset({
    "about", "also", "and", "are", "evidence", "findings", "for", "from",
    "report", "section", "source", "study", "that", "the", "their", "these",
    "this", "those", "using", "was", "were", "which", "with",
})


def relation_evidence_packs_enabled() -> bool:
    """Return the central default-off switch at call time."""

    return (resolve("PG_RELATION_EVIDENCE_PACKS") or "").strip().lower() in _TRUE_VALUES


def _get(value: Any, name: str, default: Any = None) -> Any:
    if isinstance(value, Mapping):
        return value.get(name, default)
    return getattr(value, name, default)


def _row_proposition(row: Mapping[str, Any]) -> str:
    return str(
        row.get("proposition")
        or row.get("claim_text")
        or row.get("statement")
        or row.get("direct_quote")
        or row.get("title")
        or ""
    ).strip()


def _tokens(text: str) -> frozenset[str]:
    return frozenset(
        token.casefold()
        for token in _TOKEN_RE.findall(str(text or ""))
        if len(token) > 2 and token.casefold() not in _STOPWORDS
    )


def _proposition_key(row: Mapping[str, Any]) -> str:
    declared = str(
        row.get("proposition_id")
        or row.get("claim_cluster_id")
        or row.get("basket_id")
        or ""
    ).strip()
    if declared:
        return declared
    words = sorted(_tokens(_row_proposition(row)))
    return " ".join(words)


def _attributes(row: Mapping[str, Any]) -> dict[str, str]:
    aliases = {
        "design": ("design", "study_design", "method"),
        "population": ("population", "sample", "cohort"),
        "measure": ("measure", "metric", "endpoint", "outcome"),
        "basis": ("observed_or_modeled", "observed_vs_modeled", "evidence_basis"),
        "period": ("period", "timeframe", "date_range"),
    }
    output: dict[str, str] = {}
    for label, names in aliases.items():
        value = next(
            (str(row.get(name) or "").strip() for name in names if str(row.get(name) or "").strip()),
            "",
        )
        if value:
            output[label] = value
    return output


def assign_conflict_owners(
    conflicts: Sequence[Mapping[str, Any]],
    plans: Sequence[Any],
) -> list[dict[str, Any]]:
    """Assign each conflict to one section using membership, vocabulary, then order."""

    output: list[dict[str, Any]] = []
    for conflict in conflicts:
        ids = {str(item) for item in (conflict.get("evidence_ids") or []) if str(item)}
        conflict_words = _tokens(" ".join(
            str(conflict.get(name) or "")
            for name in ("subject", "predicate", "measure", "reason")
        ))
        scored: list[tuple[int, int, int, Any]] = []
        for index, plan in enumerate(plans):
            plan_ids = {str(item) for item in (_get(plan, "ev_ids", []) or [])}
            plan_words = _tokens(
                f"{_get(plan, 'title', '')} {_get(plan, 'focus', '')}"
            )
            scored.append((
                len(ids & plan_ids),
                len(conflict_words & plan_words),
                -index,
                plan,
            ))
        copied = dict(conflict)
        if scored:
            owner = max(scored, key=lambda item: item[:3])[3]
            copied["section_title"] = str(_get(owner, "title", "") or "")
        output.append(copied)
    return output


def build_relation_evidence_packs(
    plans: Sequence[Any],
    evidence_pool: Mapping[str, Mapping[str, Any]],
    conflicts: Sequence[Mapping[str, Any]],
) -> tuple[dict[str, str], str, list[dict[str, Any]]]:
    """Build section packs and the report-wide map without changing membership."""

    owned_conflicts = assign_conflict_owners(conflicts, plans)
    conflicts_by_id: dict[str, list[dict[str, Any]]] = {}
    for conflict in owned_conflicts:
        for evidence_id in conflict.get("evidence_ids") or []:
            conflicts_by_id.setdefault(str(evidence_id), []).append(conflict)

    section_blocks: dict[str, str] = {}
    global_entries: list[dict[str, Any]] = []
    observed_membership: list[str] = []
    for plan in plans:
        title = str(_get(plan, "title", "") or "")
        groups: dict[str, dict[str, Any]] = {}
        for evidence_id in _get(plan, "ev_ids", []) or []:
            evidence_id = str(evidence_id)
            row = evidence_pool.get(evidence_id)
            if not isinstance(row, Mapping):
                continue
            observed_membership.append(evidence_id)
            key = _proposition_key(row) or evidence_id
            group = groups.setdefault(key, {
                "proposition": _row_proposition(row),
                "supporting_evidence_ids": [],
                "contradicting_evidence_ids": [],
                "source_attributes": [],
            })
            group["supporting_evidence_ids"].append(evidence_id)
            attributes = _attributes(row)
            if attributes:
                group["source_attributes"].append({
                    "evidence_id": evidence_id,
                    **attributes,
                })
            for conflict in conflicts_by_id.get(evidence_id, []):
                if conflict.get("section_title") != title:
                    continue
                group["contradicting_evidence_ids"].extend(
                    other for other in conflict.get("evidence_ids") or []
                    if str(other) != evidence_id
                )
                group["conflict_reason"] = str(conflict.get("reason") or "")
        entries = list(groups.values())
        for entry in entries:
            entry["supporting_evidence_ids"] = list(dict.fromkeys(
                entry["supporting_evidence_ids"]
            ))
            entry["contradicting_evidence_ids"] = list(dict.fromkeys(
                entry["contradicting_evidence_ids"]
            ))
            global_entries.append({"section": title, **entry})
        section_blocks[title] = json.dumps(entries, ensure_ascii=False, sort_keys=True)

    expected_membership = [
        str(evidence_id)
        for plan in plans
        for evidence_id in (_get(plan, "ev_ids", []) or [])
        if str(evidence_id) in evidence_pool
    ]
    assert observed_membership == expected_membership
    global_map = json.dumps(global_entries, ensure_ascii=False, sort_keys=True)
    return section_blocks, global_map, owned_conflicts


def is_synthesis_plan(plan: Any) -> bool:
    """Detect the prompt-defined cross-section role from its own title/focus."""

    words = _tokens(f"{_get(plan, 'title', '')} {_get(plan, 'focus', '')}")
    return bool(words & {"synthesis", "cross-study", "integration", "convergence"})


def relation_context_for_plan(
    plan: Any,
    section_blocks: Mapping[str, str],
    global_map: str,
) -> tuple[str, str]:
    """Return local framing and, only for the synthesis role, the global map."""

    title = str(_get(plan, "title", "") or "")
    return section_blocks.get(title, ""), global_map if is_synthesis_plan(plan) else ""
